svg.script:
(function () {
  var svg = document.documentElement;
  var W = [3, 7, 15];
  var keys = [document.getElementById('k0'), document.getElementById('k1'), document.getElementById('k2')];
  var bar = document.getElementById('bar'), bv = document.getElementById('bv');
  var kg = document.getElementById('kg'), kin = document.getElementById('kin');
  var fb = document.getElementById('fb'), ro = document.getElementById('ro');
  var ov = document.getElementById('ov');
  var PX0 = 64, PPT = 18, MAXD = 32, WALL = 16;
  function upd(d) {
    d = Math.max(0, Math.min(MAXD, Math.round(d)));
    var m = 0;
    for (var i = 0; i < 3; i++) {
      keys[i].setAttribute('transform', 'rotate(' + (W[i] * d) + ')');
      m += Math.cos(W[i] * d * Math.PI / 180);
    }
    m = m / 3;
    bar.setAttribute('width', Math.max(0, m) * 240);
    var pct = Math.round(m * 100);
    bv.textContent = pct + '%';
    kg.setAttribute('transform', 'translate(' + (PX0 + PPT * d) + ',328)');
    fb.setAttribute('width', PPT * d);
    ro.textContent = 'offset m − n = ' + d + ' tokens — RoPE match ' + pct + '% · NoPE match 100%' +
      (d > WALL ? ' — angles unseen in training' : '');
  }
  function toX(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }
  var drag = false;
  ov.addEventListener('pointerdown', function (e) { drag = true; kin.setAttribute('class', ''); ov.setPointerCapture(e.pointerId); upd((toX(e) - PX0) / PPT); });
  ov.addEventListener('pointermove', function (e) { if (drag || e.pointerType === 'mouse') { kin.setAttribute('class', ''); upd((toX(e) - PX0) / PPT); } });
  addEventListener('pointerup', function () { drag = false; });
  upd(6);
})();
